/**
 * Order Module Types
 *
 * Type definitions for the Order module including:
 * - Order, OrderItem DTOs
 * - Table, Zone, QRCode types
 * - Customer, Feedback types
 * - ServiceRequest types
 * - Event payloads and hook contexts
 *
 * @module modules/order/types
 *
 * @example
 * ```typescript
 * import type {
 *   Order,
 *   OrderItem,
 *   Table,
 *   CreateOrderRequest,
 * } from '@/modules/order/order.types';
 *
 * async function createOrder(data: CreateOrderRequest): Promise<Order> { ... }
 * ```
 */

import type { Decimal } from '@prisma/client/runtime/library';

// -----------------------------------------------------------------------------
// Enums (matching Prisma schema)
// -----------------------------------------------------------------------------

/**
 * Order status values
 */
export type OrderStatus =
  | 'PENDING'
  | 'CONFIRMED'
  | 'PREPARING'
  | 'READY'
  | 'DELIVERED'
  | 'COMPLETED'
  | 'CANCELLED';

/**
 * Order type values
 */
export type OrderType = 'DINE_IN' | 'TAKEAWAY' | 'DELIVERY';

/**
 * Order item status values
 */
export type OrderItemStatus = 'PENDING' | 'PREPARING' | 'READY' | 'SERVED';

/**
 * Table status values
 */
export type TableStatus = 'AVAILABLE' | 'OCCUPIED' | 'RESERVED';

/**
 * QR code type values
 */
export type QRCodeType = 'MENU' | 'TABLE' | 'CAMPAIGN';

// -----------------------------------------------------------------------------
// Zone Types
// -----------------------------------------------------------------------------

/**
 * Zone entity (table grouping)
 */
export interface Zone {
  /** Zone ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Zone name */
  name: string;
  /** Zone color (hex) */
  color: string | null;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Zone with relations
 */
export interface ZoneWithRelations extends Zone {
  /** Tables in this zone */
  tables?: Table[];
}

/**
 * Create zone request
 */
export interface CreateZoneRequest {
  /** Zone name */
  name: string;
  /** Zone color (hex) */
  color?: string;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update zone request
 */
export interface UpdateZoneRequest {
  /** Zone name */
  name?: string;
  /** Zone color (hex) */
  color?: string | null;
  /** Sort order */
  sortOrder?: number;
}

/**
 * List zones query parameters
 */
export interface ListZonesQuery {
  /** Search by name */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// Table Types
// -----------------------------------------------------------------------------

/**
 * Table entity
 */
export interface Table {
  /** Table ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Branch ID (optional) */
  branchId: string | null;
  /** Zone ID (optional) */
  zoneId: string | null;
  /** Table number */
  number: string;
  /** Seating capacity */
  capacity: number;
  /** Table status */
  status: TableStatus;
  /** Current order ID */
  currentOrderId: string | null;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Table with relations
 */
export interface TableWithRelations extends Table {
  /** Zone */
  zone?: Zone | null;
  /** QR code */
  qrCode?: QRCode | null;
  /** Current order */
  currentOrder?: Order | null;
  /** Order history */
  orders?: Order[];
  /** Service requests */
  serviceRequests?: ServiceRequest[];
}

/**
 * Create table request
 */
export interface CreateTableRequest {
  /** Table number */
  number: string;
  /** Seating capacity */
  capacity: number;
  /** Branch ID (optional) */
  branchId?: string;
  /** Zone ID (optional) */
  zoneId?: string;
  /** Initial status */
  status?: TableStatus;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update table request
 */
export interface UpdateTableRequest {
  /** Table number */
  number?: string;
  /** Seating capacity */
  capacity?: number;
  /** Branch ID */
  branchId?: string | null;
  /** Zone ID */
  zoneId?: string | null;
  /** Table status */
  status?: TableStatus;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Change table status request
 */
export interface ChangeTableStatusRequest {
  /** New status */
  status: TableStatus;
}

/**
 * List tables query parameters
 */
export interface ListTablesQuery {
  /** Filter by branch ID */
  branchId?: string;
  /** Filter by zone ID */
  zoneId?: string;
  /** Filter by status */
  status?: TableStatus;
  /** Search by number */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'number' | 'capacity' | 'sortOrder' | 'createdAt';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// QR Code Types
// -----------------------------------------------------------------------------

/**
 * QR Code entity
 */
export interface QRCode {
  /** QR Code ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Menu ID */
  menuId: string;
  /** Table ID (optional) */
  tableId: string | null;
  /** Unique code */
  code: string;
  /** QR code type */
  type: QRCodeType;
  /** Target URL */
  url: string;
  /** Image URL */
  imageUrl: string | null;
  /** Total scan count */
  scansCount: number;
  /** Active status */
  isActive: boolean;
  /** Expiration date */
  expiresAt: Date | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * QR Code with relations
 */
export interface QRCodeWithRelations extends QRCode {
  /** Associated table */
  table?: Table | null;
  /** Recent scans */
  scans?: QRScan[];
}

/**
 * QR Scan entity
 */
export interface QRScan {
  /** Scan ID */
  id: string;
  /** QR Code ID */
  qrCodeId: string;
  /** Organization ID */
  organizationId: string;
  /** User agent */
  userAgent: string | null;
  /** IP address */
  ipAddress: string | null;
  /** Referrer URL */
  referrer: string | null;
  /** Device type */
  deviceType: string | null;
  /** Browser name */
  browser: string | null;
  /** Operating system */
  os: string | null;
  /** Country */
  country: string | null;
  /** City */
  city: string | null;
  /** Additional metadata */
  metadata: Record<string, unknown>;
  /** Scan timestamp */
  scannedAt: Date;
}

/**
 * Create QR code request
 */
export interface CreateQRCodeRequest {
  /** Menu ID */
  menuId: string;
  /** Table ID (optional, for table QR codes) */
  tableId?: string;
  /** QR code type */
  type?: QRCodeType;
  /** Expiration date */
  expiresAt?: Date;
}

/**
 * Update QR code request
 */
export interface UpdateQRCodeRequest {
  /** Active status */
  isActive?: boolean;
  /** Expiration date */
  expiresAt?: Date | null;
}

/**
 * List QR codes query parameters
 */
export interface ListQRCodesQuery {
  /** Filter by menu ID */
  menuId?: string;
  /** Filter by table ID */
  tableId?: string;
  /** Filter by type */
  type?: QRCodeType;
  /** Filter by active status */
  isActive?: boolean;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// Order Types
// -----------------------------------------------------------------------------

/**
 * Order entity
 */
export interface Order {
  /** Order ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Branch ID (optional) */
  branchId: string | null;
  /** Order number */
  orderNumber: string;
  /** Table ID (optional) */
  tableId: string | null;
  /** Customer ID (optional) */
  customerId: string | null;
  /** Staff ID who processed the order */
  staffId: string | null;
  /** Order status */
  status: OrderStatus;
  /** Order type */
  type: OrderType;
  /** Subtotal amount */
  subtotal: Decimal | string | number;
  /** Tax amount */
  taxAmount: Decimal | string | number;
  /** Discount amount */
  discountAmount: Decimal | string | number;
  /** Total amount */
  totalAmount: Decimal | string | number;
  /** Currency code */
  currency: string;
  /** Order notes */
  notes: string | null;
  /** Confirmed timestamp */
  confirmedAt: Date | null;
  /** Prepared timestamp */
  preparedAt: Date | null;
  /** Delivered timestamp */
  deliveredAt: Date | null;
  /** Completed timestamp */
  completedAt: Date | null;
  /** Cancelled timestamp */
  cancelledAt: Date | null;
  /** Cancel reason */
  cancelReason: string | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Order with relations
 */
export interface OrderWithRelations extends Order {
  /** Order items */
  items?: OrderItem[];
  /** Associated table */
  table?: Table | null;
  /** Customer info */
  customer?: Customer | null;
  /** Feedback */
  feedback?: Feedback | null;
}

/**
 * Order item entity
 */
export interface OrderItem {
  /** Item ID */
  id: string;
  /** Order ID */
  orderId: string;
  /** Product ID */
  productId: string;
  /** Variant ID (optional) */
  variantId: string | null;
  /** Product name (snapshot) */
  productName: string;
  /** Variant name (snapshot) */
  variantName: string | null;
  /** Quantity */
  quantity: number;
  /** Unit price */
  unitPrice: Decimal | string | number;
  /** Total price (unit * quantity + modifiers) */
  totalPrice: Decimal | string | number;
  /** Selected modifiers (JSON snapshot) */
  modifiers: OrderItemModifier[];
  /** Item notes */
  notes: string | null;
  /** Item status */
  status: OrderItemStatus;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Order item modifier (stored as JSON)
 */
export interface OrderItemModifier {
  /** Modifier ID */
  id: string;
  /** Modifier name */
  name: string;
  /** Modifier price */
  price: number;
  /** Quantity */
  quantity: number;
}

/**
 * Create order request
 */
export interface CreateOrderRequest {
  /** Table ID (optional) */
  tableId?: string;
  /** Customer ID (optional) */
  customerId?: string;
  /** Order type */
  type?: OrderType;
  /** Order notes */
  notes?: string;
  /** Order items */
  items: CreateOrderItemRequest[];
}

/**
 * Create order item request
 */
export interface CreateOrderItemRequest {
  /** Product ID */
  productId: string;
  /** Variant ID (optional) */
  variantId?: string;
  /** Quantity */
  quantity: number;
  /** Item notes */
  notes?: string;
  /** Selected modifier IDs with quantities */
  modifiers?: Array<{
    id: string;
    quantity?: number;
  }>;
}

/**
 * Update order request
 */
export interface UpdateOrderRequest {
  /** Order notes */
  notes?: string | null;
  /** Staff ID */
  staffId?: string | null;
}

/**
 * Change order status request
 */
export interface ChangeOrderStatusRequest {
  /** New status */
  status: OrderStatus;
  /** Reason (for cancellation) */
  reason?: string;
}

/**
 * Add order item request
 */
export interface AddOrderItemRequest extends CreateOrderItemRequest {}

/**
 * Update order item request
 */
export interface UpdateOrderItemRequest {
  /** Quantity */
  quantity?: number;
  /** Item notes */
  notes?: string | null;
  /** Item status */
  status?: OrderItemStatus;
}

/**
 * List orders query parameters
 */
export interface ListOrdersQuery {
  /** Filter by status */
  status?: OrderStatus;
  /** Filter by type */
  type?: OrderType;
  /** Filter by branch ID */
  branchId?: string;
  /** Filter by table ID */
  tableId?: string;
  /** Filter by customer ID */
  customerId?: string;
  /** Filter by date range (start) */
  dateFrom?: Date;
  /** Filter by date range (end) */
  dateTo?: Date;
  /** Search by order number */
  search?: string;
  /** Include relations */
  include?: Array<'items' | 'table' | 'customer' | 'feedback'>;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'orderNumber' | 'totalAmount' | 'createdAt' | 'status';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Customer Types
// -----------------------------------------------------------------------------

/**
 * Customer entity
 */
export interface Customer {
  /** Customer ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Email address */
  email: string | null;
  /** Phone number */
  phone: string | null;
  /** First name */
  firstName: string | null;
  /** Last name */
  lastName: string | null;
  /** Avatar URL */
  avatar: string | null;
  /** Total orders count */
  totalOrders: number;
  /** Total amount spent */
  totalSpent: Decimal | string | number;
  /** Last order timestamp */
  lastOrderAt: Date | null;
  /** Customer notes */
  notes: string | null;
  /** Additional metadata */
  metadata: Record<string, unknown>;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Customer with relations
 */
export interface CustomerWithRelations extends Customer {
  /** Order history */
  orders?: Order[];
  /** Feedback history */
  feedback?: Feedback[];
  /** Loyalty points */
  loyaltyPoints?: LoyaltyPoint[];
}

/**
 * Create customer request
 */
export interface CreateCustomerRequest {
  /** Email address */
  email?: string;
  /** Phone number */
  phone?: string;
  /** First name */
  firstName?: string;
  /** Last name */
  lastName?: string;
  /** Customer notes */
  notes?: string;
  /** Additional metadata */
  metadata?: Record<string, unknown>;
}

/**
 * Update customer request
 */
export interface UpdateCustomerRequest {
  /** Email address */
  email?: string | null;
  /** Phone number */
  phone?: string | null;
  /** First name */
  firstName?: string | null;
  /** Last name */
  lastName?: string | null;
  /** Avatar URL */
  avatar?: string | null;
  /** Customer notes */
  notes?: string | null;
  /** Additional metadata */
  metadata?: Record<string, unknown>;
}

/**
 * List customers query parameters
 */
export interface ListCustomersQuery {
  /** Search by email, phone, or name */
  search?: string;
  /** Filter by minimum orders */
  minOrders?: number;
  /** Filter by minimum spent */
  minSpent?: number;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'totalOrders' | 'totalSpent' | 'lastOrderAt' | 'createdAt';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Service Request Types
// -----------------------------------------------------------------------------

/**
 * Service request type values
 */
export type ServiceRequestType = 'CALL_WAITER' | 'REQUEST_BILL' | 'CUSTOM';

/**
 * Service request entity
 */
export interface ServiceRequest {
  /** Request ID */
  id: string;
  /** Table ID */
  tableId: string;
  /** Organization ID */
  organizationId: string;
  /** Request type */
  type: string;
  /** Custom message */
  message: string | null;
  /** Resolved status */
  isResolved: boolean;
  /** Resolved timestamp */
  resolvedAt: Date | null;
  /** Resolved by user ID */
  resolvedById: string | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Service request with relations
 */
export interface ServiceRequestWithRelations extends ServiceRequest {
  /** Associated table */
  table?: Table;
}

/**
 * Create service request
 */
export interface CreateServiceRequest {
  /** Table ID */
  tableId: string;
  /** Request type */
  type: ServiceRequestType;
  /** Custom message */
  message?: string;
}

/**
 * List service requests query
 */
export interface ListServiceRequestsQuery {
  /** Filter by table ID */
  tableId?: string;
  /** Filter by resolved status */
  isResolved?: boolean;
  /** Filter by type */
  type?: ServiceRequestType;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// Feedback Types
// -----------------------------------------------------------------------------

/**
 * Feedback entity
 */
export interface Feedback {
  /** Feedback ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Order ID */
  orderId: string;
  /** Customer ID (optional) */
  customerId: string | null;
  /** Rating (1-5) */
  rating: number;
  /** Comment text */
  comment: string | null;
  /** Public visibility */
  isPublic: boolean;
  /** Additional metadata */
  metadata: Record<string, unknown>;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Feedback with relations
 */
export interface FeedbackWithRelations extends Feedback {
  /** Associated order */
  order?: Order;
  /** Customer info */
  customer?: Customer | null;
}

/**
 * Create feedback request
 */
export interface CreateFeedbackRequest {
  /** Order ID */
  orderId: string;
  /** Rating (1-5) */
  rating: number;
  /** Comment text */
  comment?: string;
  /** Make feedback public */
  isPublic?: boolean;
}

/**
 * List feedback query
 */
export interface ListFeedbackQuery {
  /** Filter by minimum rating */
  minRating?: number;
  /** Filter by maximum rating */
  maxRating?: number;
  /** Filter by public status */
  isPublic?: boolean;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'rating' | 'createdAt';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Loyalty Point Types
// -----------------------------------------------------------------------------

/**
 * Loyalty point entity
 */
export interface LoyaltyPoint {
  /** Point entry ID */
  id: string;
  /** Customer ID */
  customerId: string;
  /** Organization ID */
  organizationId: string;
  /** Points amount */
  points: number;
  /** Reason for points */
  reason: string;
  /** Related order ID */
  orderId: string | null;
  /** Expiration date */
  expiresAt: Date | null;
  /** Creation timestamp */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Event Payloads
// -----------------------------------------------------------------------------

/**
 * Order created event payload
 */
export interface OrderCreatedEvent {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Organization ID */
  organizationId: string;
  /** Order type */
  type: OrderType;
  /** Total amount */
  totalAmount: number;
  /** Table ID */
  tableId: string | null;
  /** Timestamp */
  timestamp: string;
}

/**
 * Order status changed event payload
 */
export interface OrderStatusChangedEvent {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Organization ID */
  organizationId: string;
  /** Previous status */
  previousStatus: OrderStatus;
  /** New status */
  newStatus: OrderStatus;
  /** Cancel reason (if cancelled) */
  cancelReason: string | null;
  /** Timestamp */
  timestamp: string;
}

/**
 * Table status changed event payload
 */
export interface TableStatusChangedEvent {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Organization ID */
  organizationId: string;
  /** Previous status */
  previousStatus: TableStatus;
  /** New status */
  newStatus: TableStatus;
  /** Timestamp */
  timestamp: string;
}

/**
 * QR code scanned event payload
 */
export interface QRCodeScannedEvent {
  /** QR Code ID */
  qrCodeId: string;
  /** Organization ID */
  organizationId: string;
  /** Menu ID */
  menuId: string;
  /** Table ID */
  tableId: string | null;
  /** Scan metadata */
  scanData: {
    deviceType: string | null;
    browser: string | null;
    country: string | null;
  };
  /** Timestamp */
  timestamp: string;
}

/**
 * Service requested event payload
 */
export interface ServiceRequestedEvent {
  /** Request ID */
  requestId: string;
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Organization ID */
  organizationId: string;
  /** Request type */
  type: string;
  /** Message */
  message: string | null;
  /** Timestamp */
  timestamp: string;
}

/**
 * Feedback submitted event payload
 */
export interface FeedbackSubmittedEvent {
  /** Feedback ID */
  feedbackId: string;
  /** Order ID */
  orderId: string;
  /** Organization ID */
  organizationId: string;
  /** Rating */
  rating: number;
  /** Has comment */
  hasComment: boolean;
  /** Timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Contexts
// -----------------------------------------------------------------------------

/**
 * Before order create hook context
 */
export interface BeforeOrderCreateContext {
  /** Create request data */
  data: CreateOrderRequest;
  /** Organization ID */
  organizationId: string;
  /** Table (if dine-in) */
  table: Table | null;
}

/**
 * After order create hook context
 */
export interface AfterOrderCreateContext {
  /** Created order */
  order: OrderWithRelations;
  /** Organization ID */
  organizationId: string;
}

/**
 * Before status change hook context
 */
export interface BeforeStatusChangeContext {
  /** Current order */
  order: Order;
  /** Current status */
  currentStatus: OrderStatus;
  /** Target status */
  targetStatus: OrderStatus;
  /** Reason (for cancellation) */
  reason: string | null;
}

/**
 * After status change hook context
 */
export interface AfterStatusChangeContext {
  /** Updated order */
  order: Order;
  /** Previous status */
  previousStatus: OrderStatus;
  /** New status */
  newStatus: OrderStatus;
}

/**
 * Before item add hook context
 */
export interface BeforeItemAddContext {
  /** Order */
  order: Order;
  /** Item data */
  itemData: CreateOrderItemRequest;
}

/**
 * After item add hook context
 */
export interface AfterItemAddContext {
  /** Updated order */
  order: OrderWithRelations;
  /** Added item */
  item: OrderItem;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * Order module settings
 */
export interface OrderModuleSettings {
  /** Default currency for prices */
  defaultCurrency: string;
  /** Order number prefix */
  orderNumberPrefix: string;
  /** Auto-complete delay after delivery (minutes) */
  autoCompleteDelayMinutes: number;
  /** Enable table ordering */
  enableTableOrdering: boolean;
  /** Enable takeaway orders */
  enableTakeaway: boolean;
  /** Enable delivery orders */
  enableDelivery: boolean;
  /** Enable service requests */
  enableServiceRequests: boolean;
  /** Require customer info */
  requireCustomerInfo: boolean;
  /** Enable feedback collection */
  enableFeedback: boolean;
  /** Feedback reminder delay (minutes) */
  feedbackReminderDelayMinutes: number;
  /** Default tax rate percentage */
  taxRate: number;
  /** Maximum items per order */
  maxItemsPerOrder: number;
  /** Maximum order note length */
  maxOrderNoteLength: number;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Order response (API)
 */
export interface OrderResponse extends Order {
  /** Item count */
  itemCount?: number;
  /** Table info */
  table?: Pick<Table, 'id' | 'number' | 'zoneId'> | null;
  /** Customer info */
  customer?: Pick<Customer, 'id' | 'firstName' | 'lastName' | 'email'> | null;
}

/**
 * Table response (API)
 */
export interface TableResponse extends Table {
  /** Zone info */
  zone?: Pick<Zone, 'id' | 'name' | 'color'> | null;
  /** QR code info */
  qrCode?: Pick<QRCode, 'id' | 'code' | 'url'> | null;
  /** Has active order */
  hasActiveOrder?: boolean;
}

/**
 * Order statistics response
 */
export interface OrderStatistics {
  /** Total orders count */
  totalOrders: number;
  /** Orders by status */
  byStatus: Record<OrderStatus, number>;
  /** Orders by type */
  byType: Record<OrderType, number>;
  /** Total revenue */
  totalRevenue: number;
  /** Average order value */
  averageOrderValue: number;
  /** Period (e.g., "today", "week", "month") */
  period: string;
}

/**
 * Kitchen display order (optimized for kitchen view)
 */
export interface KitchenOrder {
  /** Order ID */
  id: string;
  /** Order number */
  orderNumber: string;
  /** Table number */
  tableNumber: string | null;
  /** Order type */
  type: OrderType;
  /** Order status */
  status: OrderStatus;
  /** Items */
  items: Array<{
    id: string;
    productName: string;
    variantName: string | null;
    quantity: number;
    modifiers: OrderItemModifier[];
    notes: string | null;
    status: OrderItemStatus;
  }>;
  /** Order notes */
  notes: string | null;
  /** Created at */
  createdAt: Date;
  /** Minutes since creation */
  waitTimeMinutes: number;
}
